function main(): void {
var callCount = 0;
var _this, _key;
var obj = {
  toJSON: function(key) {
    callCount += 1;
    _this = this;
    _key = key;
  },
};

console.log(JSON.stringify(obj));
console.log(callCount);
console.log(_this);
console.log(_key);

console.log(JSON.stringify([1, obj, 3]));
console.log(callCount);
console.log(_this);
console.log(_key);

console.log(JSON.stringify({key: obj}));
console.log(callCount);
console.log(_this);
console.log(_key);
}

